package wordcount

import (
	"maps"
	"testing"
)

func TestWordCount(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  map[string]int
	}{
		{
			name:  "empty string",
			input: "",
			want:  map[string]int{},
		},
		{
			name:  "single word",
			input: "hello",
			want:  map[string]int{"hello": 1},
		},
		{
			name:  "mixed case",
			input: "Hello HELLO hello",
			want:  map[string]int{"hello": 3},
		},
		{
			name:  "punctuation",
			input: "hello, world! how's it?",
			want:  map[string]int{"hello": 1, "world": 1, "how's": 1, "it": 1},
		},
		{
			name:  "repeated words",
			input: "the quick brown fox jumps over the lazy dog",
			want: map[string]int{
				"the": 2, "quick": 1, "brown": 1, "fox": 1,
				"jumps": 1, "over": 1, "lazy": 1, "dog": 1,
			},
		},
		{
			name:  "multi-word sentence with various punctuation",
			input: "Don't worry, it's fine! Don't worry.",
			want: map[string]int{
				"don't": 2, "worry": 2, "it's": 1, "fine": 1,
			},
		},
		{
			name:  "multiple spaces and tabs",
			input: "hello   world\t\tgo",
			want:  map[string]int{"hello": 1, "world": 1, "go": 1},
		},
		{
			name:  "only punctuation",
			input: "... !!! ???",
			want:  map[string]int{},
		},
		{
			name:  "words with numbers",
			input: "test123 Test123 TEST123",
			want:  map[string]int{"test123": 3},
		},
		{
			name:  "single character words",
			input: "a B c A b C",
			want:  map[string]int{"a": 2, "b": 2, "c": 2},
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := WordCount(tc.input)

			if !maps.Equal(got, tc.want) {
				t.Errorf("WordCount(%q) = %v, want %v", tc.input, got, tc.want)
			}
		})
	}
}

